CREATE procedure [UpdateInheritDmsObjectPermissions] ( @objId bigint, -- это идентификатор объекта для которого нужно обновить привилегии @onlyChildren bit -- обновлять только в дочерних элементах ) as begin
declare @usermask bigint; set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 declare @objqueue table (id bigint, folder bigint, creationAuthor bigint);
with rec(Id, Folder, CreationAuthor) as ( select d.Id, d.Folder, d.CreationAuthor from DmsObject d where d.Id = @objId union all select dc.Id, dc.Folder, dc.CreationAuthor from DmsObject dc inner join rec on rec.Id = dc.Folder and dc.InheritPermissions = 1 ) insert into @objqueue (id, folder, creationAuthor) select * from rec where @onlyChildren = 0 or id != @objId
while((select COUNT(*) from @objqueue) > 0) begin declare @currentId bigint, @parentId bigint, @creationAuthor bigint; select top 1 @currentId = id, @parentId = folder, @creationAuthor = creationAuthor from @objqueue
if @parentId is not null begin -- TODO использовать merge для минимизации изменений! delete from DmsObjectPermission where DmsObject = @currentId and InheritedFromFolder is not null;
declare @insTable table ( [Id] [bigint] NOT NULL Primary KEY, [Uid] [uniqueidentifier] NULL, [DmsObject] [bigint] NULL, [PermissionId] [uniqueidentifier] NULL, [User] [bigint] NULL, [Group] [bigint] NULL, [OrganizationItemPosition] [bigint] NULL, [OrganizationItemEmployee] [bigint] NULL, [UserSecuritySetCacheId] [bigint] NULL, [PermissionRole] [uniqueidentifier] NULL, [InheritedFromFolder] [bigint] NULL );
declare @insCounter bigint, @insStartId bigint, @insEndId bigint;
insert into @insTable ([Id], [Uid], DmsObject, [Group], InheritedFromFolder, OrganizationItemEmployee, OrganizationItemPosition, PermissionId, PermissionRole, [User], UserSecuritySetCacheId) select ROW_NUMBER() over (order by [Id]) - 1, NEWID(), @currentId, pdp.[Group], case when pdp.InheritedFromFolder is null then @parentId else pdp.InheritedFromFolder end, pdp.OrganizationItemEmployee, pdp.OrganizationItemPosition, pdp.PermissionId, pdp.PermissionRole, (case when pdp.PermissionRole = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then @creationAuthor else pdp.[User] end) as [User], (case when pdp.PermissionRole = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then (@creationAuthor|@usermask) else pdp.UserSecuritySetCacheId end) as UserSecuritySetCacheId from DmsObjectPermission pdp where pdp.DmsObject = @parentId;
SELECT @insCounter = COUNT(Id) FROM @insTable;
EXECUTE [G_GenId] 'DmsObjectPermission', @insCounter, @insStartId out, @insEndId out;
insert into DmsObjectPermission ([Id], [Uid], DmsObject, [Group], InheritedFromFolder, OrganizationItemEmployee, OrganizationItemPosition, PermissionId, PermissionRole, [User], UserSecuritySetCacheId ) select @insStartId + [Id], [Uid], DmsObject, [Group], InheritedFromFolder, OrganizationItemEmployee, OrganizationItemPosition, PermissionId, PermissionRole, [User], UserSecuritySetCacheId from @insTable;
delete from @insTable; end delete from @objqueue where id = @currentId; end end

CREATE procedure [UpdateInheritDmsObjectPermissionsPatch]
(
  @objId bigint,
  @permsStr varchar(max)
)
as
begin
declare @addPatch int = 0;
declare @remPatch int = 1;

create table #permsTableTemp (
	[PermissionId] [uniqueidentifier] NULL,
	[User] [bigint] NULL,
	[Group] [bigint] NULL,
	[OrganizationItemPosition] [bigint] NULL,
	[OrganizationItemEmployee] [bigint] NULL,
	[UserSecuritySetCacheId] [bigint] NULL,
	[PermissionRole] [uniqueidentifier] NULL,
	[InheritedFromFolder] [bigint] NULL,
	[PatchType] [int] NULL
);
create index IX_permsTableTempIndex ON #permsTableTemp ([PatchType]);
create table #dmsObjects (id bigint not null Primary KEY, folder bigint, CreationAuthor bigint);

declare @separator int;
declare @itemStr varchar(max);

declare @permissionId uniqueidentifier;
declare @userId bigint;
declare @groupId bigint;
declare @orgItemPos bigint;
declare @orgItemEmp bigint;
declare @setCacheId bigint;
declare @permissionRole uniqueidentifier;
declare @inheritedFromFolder bigint;
declare @patchType int;

 -- parse permsStr
while patindex('%;%', @permsStr) > 0
begin
	set @separator = patindex('%;%', @permsStr);
	set @itemStr = left(@permsStr, @separator - 1);
	set @permsStr = stuff(@permsStr, 1, @separator, '');

	set @separator = patindex('%:%', @itemStr);
	if (@separator > 0)
	begin
		-- permission
		set @permissionId = cast(left(@itemStr, @separator - 1) as uniqueidentifier);
		set @itemStr = stuff(@itemStr, 1 , @separator, '');

		-- user
		set @separator = patindex('%:%', @itemStr);
		set @userId = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- group
		set @separator = patindex('%:%', @itemStr);
		set @groupId = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- org item pos
		set @separator = patindex('%:%', @itemStr);
		set @orgItemPos = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- org item emp
		set @separator = patindex('%:%', @itemStr);
		set @orgItemEmp = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- set cache id
		set @separator = patindex('%:%', @itemStr);
		set @setCacheId = cast(left(@itemStr, @separator - 1) as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- permission role
		set @separator = patindex('%:%', @itemStr);
		set @permissionRole = cast(left(@itemStr, @separator - 1) as uniqueidentifier);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- inhertited from folder
		set @separator = patindex('%:%', @itemStr);
		set @inheritedFromFolder = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);

		-- patch type
		set @patchType = cast(stuff(@itemStr, 1, @separator, '') as int);

		insert into #permsTableTemp values(@permissionId, @userId, @groupId, @orgItemPos, @orgItemEmp, @setCacheId, @permissionRole, @inheritedFromFolder, @patchType);
	end	
end

 if (exists(select * from #permsTableTemp))
 begin
	declare @creationAuthor bigint;
	declare @insCounter bigint, @insStartId bigint, @insEndId bigint;
	declare @usermask bigint = 72057594037927936; -- 1 << 56;

	-- unroll from root 
	with rec(Id, Folder, CreationAuthor) as 
	(
		select d.Id, d.Folder, d.CreationAuthor from DmsObject d where d.Id = @objId
		union all 
		select dc.Id, dc.Folder, dc.CreationAuthor from DmsObject dc 
		inner join rec  on rec.Id = dc.Folder and dc.InheritPermissions = 1
	)
	insert into #dmsObjects (id, folder, CreationAuthor)
	select * from rec where id != @objId

	if (exists(select * from #permsTableTemp where PatchType = @remPatch))
	begin
		-- remove
		delete p from DmsObjectPermission p
		inner join #dmsObjects d on d.Id = p.DmsObject 
		inner join #permsTableTemp r on (
			p.[PermissionId] = r.[PermissionId] and
			(p.[User] = (case when r.PermissionRole = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then d.CreationAuthor else r.[User] end) or p.[User] is null and r.[User] is null) and
			(p.[Group] = r.[Group] or p.[Group] is null and r.[Group] is null) and
			(p.OrganizationItemPosition = r.OrganizationItemPosition or p.OrganizationItemPosition is null and r.OrganizationItemPosition is null) and
			(p.OrganizationItemEmployee = r.OrganizationItemEmployee or p.OrganizationItemEmployee is null and r.OrganizationItemEmployee is null) and
			p.UserSecuritySetCacheId = (case when r.PermissionRole = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then (d.CreationAuthor|@usermask) else r.UserSecuritySetCacheId end) and
			p.PermissionRole = r.PermissionRole and
			p.InheritedFromFolder = case when r.InheritedFromFolder is null then @objId else r.InheritedFromFolder end)
		where r.PatchType = @remPatch
	end

	-- insert
	if (exists(select * from #permsTableTemp where PatchType = @addPatch))
	begin
		declare @insTable table (
			[Id] [bigint] NOT NULL Primary KEY,
			[DmsObject] [bigint] NULL,
			[PermissionId] [uniqueidentifier] NULL,
			[User] [bigint] NULL,
			[Group] [bigint] NULL,
			[OrganizationItemPosition] [bigint] NULL,
			[OrganizationItemEmployee] [bigint] NULL,
			[UserSecuritySetCacheId] [bigint] NULL,
			[PermissionRole] [uniqueidentifier] NULL,
			[InheritedFromFolder] [bigint] NULL
		);
		insert into @insTable 
		select 
			ROW_NUMBER() over(order by [Id]) - 1,
			d.[Id],
			a.PermissionId,
			(case when a.PermissionRole = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then d.CreationAuthor else a.[User] end) as [User],
			a.[Group],
			a.OrganizationItemPosition, 
			a.OrganizationItemEmployee, 
			(case when a.PermissionRole = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then (d.CreationAuthor|@usermask) else a.UserSecuritySetCacheId end) as UserSecuritySetCacheId,			
			a.PermissionRole,
			case when a.InheritedFromFolder is null then @objId else a.InheritedFromFolder end
		from #dmsObjects d
		cross join #permsTableTemp a
		where a.PatchType = @addPatch

		delete t from @insTable t 
		inner join DmsObjectPermission p
			on t.DmsObject = p.DmsObject
			and t.PermissionId = p.PermissionId
			and (t.[User] = p.[User] or t.[User] is null and p.[User] is null) 
			and (t.[Group] = p.[Group] or t.[Group] is null and p.[Group] is null)
			and (t.OrganizationItemPosition = p.OrganizationItemPosition or t.OrganizationItemPosition is null and p.OrganizationItemPosition is null)
			and (t.OrganizationItemEmployee = p.OrganizationItemEmployee or t.OrganizationItemEmployee is null and p.OrganizationItemEmployee is null)
			and t.UserSecuritySetCacheId = p.UserSecuritySetCacheId
			and t.PermissionRole = p.PermissionRole
			and (t.InheritedFromFolder = p.InheritedFromFolder or t.InheritedFromFolder is null and p.InheritedFromFolder is null) 

		select @insCounter = count(Id) FROM @insTable;

		execute [G_GenId] 'DmsObjectPermission', @insCounter, @insStartId out, @insEndId out;

		insert into DmsObjectPermission (
			[Id], 
			[Uid],
			DmsObject,
			[Group],
			InheritedFromFolder,
			OrganizationItemEmployee, 
			OrganizationItemPosition,
			PermissionId,
			PermissionRole,
			[User],
			UserSecuritySetCacheId)
		select 
			@insStartId + (ROW_NUMBER() over (order by [Id]) - 1),
			NEWID(),
			t.DmsObject,
			t.[Group],
			t.InheritedFromFolder,
			t.OrganizationItemEmployee, 
			t.OrganizationItemPosition, 
			t.PermissionId, 
			t.PermissionRole, 
			t.[User],
			t.UserSecuritySetCacheId			
		from @insTable t
	end
	drop table #dmsObjects;
	drop table #permsTableTemp;
end

end

CREATE FUNCTION GetPermissionToAdd(@leftObject bigint, @rightObject bigint)
RETURNS @result TABLE (		
	[UserId] [bigint] NULL,
	[GroupId] [bigint] NULL,
	[OrganizationItemPositionId] [bigint] NULL,
	[OrganizationItemEmployeeId] [bigint] NULL	
)
AS
begin
    declare 
	   @DmsObject bigint,
	   @PermissionId uniqueidentifier,
	   @User bigint,
	   @Group bigint,
	   @OrganizationItemPosition bigint,
	   @OrganizationItemEmployee bigint,
	   @UserSecuritySetCacheId bigint,
	   @PermissionRole uniqueidentifier;   

	declare @tmpCount bigint, @tmpId bigint, @hasPermission int, @readPermission uniqueidentifier;
	declare @includeInGroup bigint, @hasChild bigint;

	set @readPermission = 'EBD6105A-AB44-404D-8B03-1D260EBB2881';

	DECLARE leftObjectPermissions CURSOR 
		LOCAL STATIC READ_ONLY FORWARD_ONLY
	FOR   
    select [PermissionId], [User], [Group], [OrganizationItemPosition], 
		[OrganizationItemEmployee], [UserSecuritySetCacheId], [PermissionRole] 
	from DmsObjectPermission  where [PermissionId] = @readPermission and [DmsObject] = @leftObject;

	OPEN leftObjectPermissions
	FETCH NEXT FROM leftObjectPermissions INTO @PermissionId, @User, @Group, @OrganizationItemPosition, @OrganizationItemEmployee, @UserSecuritySetCacheId, @PermissionRole
	WHILE @@FETCH_STATUS = 0
	BEGIN 
		if (@User is not null) 
		begin 
		   set @hasPermission = (select count(*) from DmsObjectPermission p
                    inner join UserSecuritySetCache c on p.UserSecuritySetCacheId = c.SetId
                    where DmsObject = @rightObject and c.UserId = @User and p.PermissionId = @readPermission);			
		end
		else if (@OrganizationItemPosition is not null)
	    begin		 
		    set @includeInGroup = (select count(*) from DmsObjectPermission p 
			inner join (
				select g.ParentGroupId, om.OrgItemId from GetGroups() g
				inner join UserGroup_OrgItem_Map om on om.GroupId = g.ParentGroupId) mm on mm.ParentGroupId = p.[Group]
			where DmsObject = @rightObject and mm.OrgItemId = @OrganizationItemPosition)

			set @hasChild = (select count(*) from DmsObjectPermission where DmsObject = @rightObject 
				    and PermissionRole = @PermissionRole
					and OrganizationItemPosition in (select OrgItemId from GetOrgItemChilds(@OrganizationItemPosition)));					

			set @hasPermission = @includeInGroup + @hasChild;
		end
		else if (@OrganizationItemEmployee is not null)
		begin				
		    set @includeInGroup = (select count(*) from DmsObjectPermission p 
			inner join (
				select g.ParentGroupId, om.OrgItemId from GetGroups() g
				inner join UserGroup_OrgItem_Map om on om.GroupId = g.ParentGroupId) mm on mm.ParentGroupId = p.[Group]
			where DmsObject = @rightObject and mm.OrgItemId = @OrganizationItemEmployee)

			set @hasChild = (select count(*) from DmsObjectPermission where DmsObject = @rightObject 
				    and PermissionRole = @PermissionRole
					and OrganizationItemEmployee in (select OrgItemId from GetOrgItemChilds(@OrganizationItemEmployee)));

			set @hasPermission = @includeInGroup + @hasChild;
	    end		
		else if (@Group is not null)
		begin
			set @hasPermission = (select count(*) from DmsObjectPermission p 
				inner join (select g.ParentGroupId, g.ChildGroupId from GetGroups() g) gg on gg.ChildGroupId = p.[Group]
				where DmsObject = @rightObject and PermissionRole = @PermissionRole 
				and gg.ParentGroupId = @Group)
		end;
		if (@hasPermission = 0)
	    begin
			insert into @result values(@User, @Group, @OrganizationItemPosition, @OrganizationItemEmployee);
		end;
		FETCH NEXT FROM leftObjectPermissions INTO @PermissionId, @User, @Group, @OrganizationItemPosition, @OrganizationItemEmployee, @UserSecuritySetCacheId, @PermissionRole
	END
	CLOSE leftObjectPermissions
	DEALLOCATE leftObjectPermissions	
	return
end


        CREATE procedure [DmsObjectPermissionPatch]
(
  @objId bigint,
  @permsStr varchar(max)
)
as
begin
declare @addPatch int = 0;
declare @remPatch int = 1;

create table #permsTableTemp (
	[PermissionId] [uniqueidentifier] NULL,
	[User] [bigint] NULL,
	[Group] [bigint] NULL,
	[OrganizationItemPosition] [bigint] NULL,
	[OrganizationItemEmployee] [bigint] NULL,
	[UserSecuritySetCacheId] [bigint] NULL,
	[PermissionRole] [uniqueidentifier] NULL,
	[InheritedFromFolder] [bigint] NULL,
	[PatchType] [int] NULL
);
create index IX_permsTableTempIndex ON #permsTableTemp ([PatchType]);
create table #dmsObjects (&&id&& bigint not null Primary KEY, &&folder&& bigint, &&CreationAuthor&& bigint);

declare @separator int;
declare @itemStr varchar(max);

declare @permissionId uniqueidentifier;
declare @userId bigint;
declare @groupId bigint;
declare @orgItemPos bigint;
declare @orgItemEmp bigint;
declare @setCacheId bigint;
declare @permissionRole uniqueidentifier;
declare @inheritedFromFolder bigint;
declare @patchType int;

 -- parse permsStr
while patindex('%;%', @permsStr) > 0
begin
	set @separator = patindex('%;%', @permsStr);
	set @itemStr = left(@permsStr, @separator - 1);
	set @permsStr = stuff(@permsStr, 1, @separator, '');

	set @separator = patindex('%:%', @itemStr);
	if (@separator > 0)
	begin
		-- permission
		set @permissionId = cast(left(@itemStr, @separator - 1) as uniqueidentifier);
		set @itemStr = stuff(@itemStr, 1 , @separator, '');

		-- user
		set @separator = patindex('%:%', @itemStr);
		set @userId = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- group
		set @separator = patindex('%:%', @itemStr);
		set @groupId = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- org item pos
		set @separator = patindex('%:%', @itemStr);
		set @orgItemPos = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- org item emp
		set @separator = patindex('%:%', @itemStr);
		set @orgItemEmp = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- set cache id
		set @separator = patindex('%:%', @itemStr);
		set @setCacheId = cast(left(@itemStr, @separator - 1) as bigint);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- permission role
		set @separator = patindex('%:%', @itemStr);
		set @permissionRole = cast(left(@itemStr, @separator - 1) as uniqueidentifier);
		set @itemStr = stuff(@itemStr, 1, @separator, '');

		-- inhertited from folder
		set @separator = patindex('%:%', @itemStr);
		set @inheritedFromFolder = cast(nullif(left(@itemStr, @separator - 1), '') as bigint);

		-- patch type
		set @patchType = cast(stuff(@itemStr, 1, @separator, '') as int);

		insert into #permsTableTemp values(@permissionId, @userId, @groupId, @orgItemPos, @orgItemEmp, @setCacheId, @permissionRole, @inheritedFromFolder, @patchType);
	end	
end

 if (exists(select * from #permsTableTemp))
 begin
	declare @creationAuthor bigint;
	declare @insCounter bigint, @insStartId bigint, @insEndId bigint;
	declare @usermask bigint = 72057594037927936; -- 1 << 56;

	-- unroll from root 
	insert into #dmsObjects (&&id&&, &&folder&&, &&CreationAuthor&&)
	select &&Id&&, &&Folder&&, &&CreationAuthor&& from &&DmsObject&& where &&id&& = @objId

	if (exists(select * from #permsTableTemp where &&PatchType&& = @remPatch))
	begin
		-- remove
		delete p from &&DmsObjectPermission&& p
		inner join #dmsObjects d on d.Id = p.&&DmsObject&& 
		inner join #permsTableTemp r on (
			p.&&PermissionId&& = r.&&PermissionId&& and
			(p.&&User&& = (case when r.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then d.&&CreationAuthor&& else r.&&User&& end) or p.&&User&& is null and r.&&User&& is null) and
			(p.&&Group&& = r.&&Group&& or p.&&Group&& is null and r.&&Group&& is null) and
			(p.&&OrganizationItemPosition&& = r.&&OrganizationItemPosition&& or p.&&OrganizationItemPosition&& is null and r.&&OrganizationItemPosition&& is null) and
			(p.&&OrganizationItemEmployee&& = r.&&OrganizationItemEmployee&& or p.&&OrganizationItemEmployee&& is null and r.&&OrganizationItemEmployee&& is null) and
			p.&&UserSecuritySetCacheId&& = (case when r.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then (d.&&CreationAuthor&&|@usermask) else r.&&UserSecuritySetCacheId&& end) and
			p.&&PermissionRole&& = r.&&PermissionRole&& and
			p.&&InheritedFromFolder&& = case when r.&&InheritedFromFolder&& is null then (select &&Folder&& From &&DmsObject&& where &&Id&& = @objId) else r.&&InheritedFromFolder&& end)
		where r.&&PatchType&& = @remPatch
	end

	-- insert
	if (exists(select * from #permsTableTemp where PatchType = @addPatch))
	begin
		declare @insTable table (
			[Id] [bigint] NOT NULL Primary KEY,
			[DmsObject] [bigint] NULL,
			[PermissionId] [uniqueidentifier] NULL,
			[User] [bigint] NULL,
			[Group] [bigint] NULL,
			[OrganizationItemPosition] [bigint] NULL,
			[OrganizationItemEmployee] [bigint] NULL,
			[UserSecuritySetCacheId] [bigint] NULL,
			[PermissionRole] [uniqueidentifier] NULL,
			[InheritedFromFolder] [bigint] NULL
		);
		insert into @insTable 
		select 
			ROW_NUMBER() over(order by [Id]) - 1,
			d.&&Id&&,
			a.&&PermissionId&&,
			(case when a.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then d.&&CreationAutho&&r else a.&&User&& end) as &&User&&,
			a.&&Group&&,
			a.&&OrganizationItemPosition&&, 
			a.&&OrganizationItemEmployee&&, 
			(case when a.&&PermissionRole&& = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then (d.&&CreationAuthor&&|@usermask) else a.&&UserSecuritySetCacheId&& end) as &&UserSecuritySetCacheId&&,			
			a.&&PermissionRole&&,
			case when a.&&InheritedFromFolder&& is null then (select &&Folder&& From &&DmsObject&& where &&Id&& = @objId) else a.&&InheritedFromFolder&& end
		from #dmsObjects d
		cross join #permsTableTemp a
		where a.&&PatchType&& = @addPatch

		delete t from @insTable t 
		inner join &&DmsObjectPermission&& p
			on t.&&DmsObject&& = p.&&DmsObject&&
			and t.&&PermissionId&& = p.&&PermissionId&&
			and (t.&&User&& = p.&&User&& or t.&&User&& is null and p.&&User&& is null) 
			and (t.&&Group&& = p.&&Group&& or t.&&Group&& is null and p.&&Group&& is null)
			and (t.&&OrganizationItemPosition&& = p.&&OrganizationItemPosition&& or t.&&OrganizationItemPosition&& is null and p.&&OrganizationItemPosition&& is null)
			and (t.&&OrganizationItemEmployee&& = p.&&OrganizationItemEmployee&& or t.&&OrganizationItemEmployee&& is null and p.&&OrganizationItemEmployee&& is null)
			and t.&&UserSecuritySetCacheId&& = p.&&UserSecuritySetCacheId&&
			and t.&&PermissionRole&& = p.&&PermissionRole&&
			and (t.&&InheritedFromFolder&& = p.&&InheritedFromFolder&& or t.&&InheritedFromFolder&& is null and p.&&InheritedFromFolder&& is null) 

		select @insCounter = count(Id) FROM @insTable;

		execute [G_GenId] 'DmsObjectPermission', @insCounter, @insStartId out, @insEndId out;

		insert into DmsObjectPermission (
			&&Id&&, 
			&&Uid&&,
			&&DmsObject&&,
			&&Group&&,
			&&InheritedFromFolder&&,
			&&OrganizationItemEmployee&&, 
			&&OrganizationItemPosition&&,
			&&PermissionId&&,
			&&PermissionRole&&,
			&&User&&,
			&&UserSecuritySetCacheId&&)
		select 
			@insStartId + (ROW_NUMBER() over (order by [Id]) - 1),
			NEWID(),
			t.&&DmsObject&&,
			t.&&Group&&,
			t.&&InheritedFromFolder&&,
			t.&&OrganizationItemEmployee&&, 
			t.&&OrganizationItemPosition&&, 
			t.&&PermissionId&&, 
			t.&&PermissionRole&&, 
			t.&&User&&,
			t.&&UserSecuritySetCacheId&&			
		from @insTable t
	end
	drop table #dmsObjects;
	drop table #permsTableTemp;
end

end
